index 0000000..1d275cc
--- /dev/null
+++ b/api/internal/search/access.go
@@ -0,0 +1,29 @@
+package search
+
+// IsFieldVisible reports whether a field should be included in metadata
+// responses (searchFields, searchOutputFields) given the caller's auth state.
+// HIDDEN fields are never visible; RESTRICTED fields require authentication.
+func IsFieldVisible(d FieldDescriptor, authenticated bool) bool {
+	switch d.Visibility {
+	case VisibilityHidden:
+		return false
+	case VisibilityRestricted:
+		return authenticated
+	default:
+		return true
+	}
+}
+
+// IsFieldSearchable reports whether a field can be used as a filter given the
+// caller's auth state. NOT_SEARCHABLE fields are never searchable; RESTRICTED
+// fields require authentication.
+func IsFieldSearchable(d FieldDescriptor, authenticated bool) bool {
+	switch d.Searchability {
+	case SearchabilityNotSearchable:
+		return false
+	case SearchabilityRestricted:
+		return authenticated
+	default:
+		return true
+	}
+}
